from datetime import datetime
import pytz
import re
from faker import Faker
import random
def task_func(epoch_milliseconds, seed=0, timezones=["UTC"]):

    fake = Faker()
    fake.seed(seed)

    dt = datetime.fromtimestamp(epoch_milliseconds / 1000)

    event_name = fake.bs()

    valid_timezones = []

    for tz in timezones:
        if tz in pytz.all_timezones:
            valid_timezones.append(tz)
        elif re.match(r'^UTC([+-]\d{1,2}:\d{2})$', tz):
            valid_timezones.append(tz)

    if not valid_timezones:
        valid_timezones = ["UTC"]

    selected_tz = random.choice(valid_timezones)

    if selected_tz in pytz.all_timezones:
        tz = pytz.timezone(selected_tz)
    else:
        offset = selected_tz[3:]
        hours, minutes = map(int, offset.split(':'))
        if selected_tz[0] == '-':
            hours, minutes = -hours, -minutes
        tz = pytz.FixedOffset((hours * 60 + minutes) * 60)

    dt_tz = tz.localize(dt)

    schedule = {
        'date': dt_tz.strftime('%Y-%m-%d'),
        'time': dt_tz.strftime('%H:%M:%S'),
        'timezone': selected_tz
    }

    return {event_name: [schedule]}

