    mean_values = {}
    for i, values in enumerate(transposed_data):
        numeric_values = [v for v in values if isinstance(v, (int, float))]
        if numeric_values:
            mean_values[f"Position {i}"] = np.mean(numeric_values)
        else:
            mean_values[f"Position {i}"] = None                                      

    with open(json_file_name, "w") as json_file:
        json.dump(mean_values, json_file, indent=4)

    return mean_values

import subprocess
import os
import sys
import time
def task_func(script_path, wait=True, *args):
    if not os.path.isfile(script_path):
        raise ValueError(f"Script '{script_path}' does not exist.")

    process = subprocess.Popen(
        [sys.executable, script_path, *args], 
        stderr=subprocess.PIPE,
        stdout=subprocess.PIPE,
    )
    if "Exception" in str(process.communicate()[1]):
        raise subprocess.CalledProcessError(process.returncode, process.args)

    if wait:
        while process.poll() is None:
            time.sleep(1)
        return process.returncode
    else:
        return None

import subprocess
import os
import sys
import time
def task_func(script_path, wait=True, *args):
    if not os.path.exists(script_path):
        raise ValueError("The script does not exist.")

    command = [sys.executable, script_path] + list(args)

    process = subprocess.Popen(command)

    if wait:
        return_code = process.wait()
        if return_code != 0:
            raise subprocess.CalledProcessError(return_code, command)
        return return_code
    else:
        return None

import os
def task_func(path: str, delimiter: str = os.path.sep) -> list:
    invalid_chars = {'<', '>', ':', '"', '|', '?', '*'}

    normalized_path = path.replace("\\", "/")

    if any(char in normalized_path for char in invalid_chars):
        raise ValueError(f"The path contains invalid characters: {invalid_chars}")

    components = normalized_path.split(delimiter)

    return components
